// PLANTILLA OFICIAL de propuesta comercial FV — vendorizada TAL CUAL de la fuente de CÁLCULOS FV.
// La salida C la puebla por REPLACES anclados (api/presentacion-fv-html) → el ESQUEMA queda idéntico.
// Para actualizar: node scripts/vendor-plantilla-propuesta.mjs (relee la fuente en FEBECOS-VENTAS).
// eslint-disable-next-line
export const PLANTILLA_PROPUESTA_FV: string = "<!-- ═══════════════════════════════════════════════════════════════════════════\r\n  PLANTILLA OFICIAL — PROPUESTA COMERCIAL · FEBECOS ENERGÍA SOLAR\r\n  Esquema de referencia = propuesta de Leo Nannini. TODO proyecto usa ESTA plantilla, MISMO esquema.\r\n  Responsable de dejarlo completo y detallado: DEV CÁLCULOS FV.\r\n  Uso: duplicar por proyecto -> cambiar SOLO los datos de abajo -> Ctrl+P -> PDF \"{NUMERO} - {cliente}.pdf\".\r\n\r\n  QUE CAMBIAR (buscar el valor de ejemplo de Leo y reemplazar):\r\n   1. HERO: \"Leonardo Nannini\" (cliente) - \"Estacion de servicio YPF - Colon, Buenos Aires\" (tipo/ubicacion)\r\n            - \"PREV-2026-0317\" (n presupuesto de Gestion) - \"06/07/2026\" (fecha) - headline h1 (opcional)\r\n   2. KPIs (4): \"~60%\" cobertura - \"$275k\" ahorro/mes - \"~2,8 anios\" repago - \"25 anios\" vida util\r\n   3. SITUACION (.factbox): factura mensual - consumo kWh/mes - tarifa - potencia - distribuidora\r\n   4. SOLUCION (.equip): equipos AGRUPADOS en ~3 lineas, SOLO cantidad + nombre + detalle corto, **SIN PRECIOS**\r\n      (ej: \"20x Paneles Trina 575Wp\" / \"1x Inversor Growatt 10kW\" / \"1x Estructura + protecciones CC/CA\").\r\n      *** NUNCA pegar aca la lista itemizada con precios: eso va en la COTIZACION/PRESUPUESTO (xlsx/Gestion), NO en la propuesta. ***\r\n      El UNICO precio de la propuesta es el TOTAL en la seccion INVERSION. + chips tecnicos (.chip).\r\n   5. GENERACION: \"~kWh/anio\" - ubicacion - arrays del <script>: \"var gen=\" (generacion PVGIS) y \"var consumo=\" (CONSUMO REAL del lugar, de la factura). El grafico es GENERACION (barras) vs CONSUMO REAL (linea roja), con el kWh de cada mes sobre la barra.\r\n   6. AHORRO (.cmp): \"$1.049.379\" (factura hoy) - \"~$774.000\" (con solar) - width de \".bar.sol\" en CSS (%=con-solar/hoy) - texto ahorro\r\n   7. RETORNO: \"var acc=\" y \"var max\" (ahorro acumulado $M) - \".invline\" bottom % (=inversion/max x100) - caption\r\n   8. INVERSION (.invest): \"USD 6.132\" (total) - lista \".incl\" (que incluye)\r\n   9. OFF-GRID: ajustar KPIs/equipos/generacion al esquema con baterias; el resto igual.\r\n\r\n  El LISTADO DETALLADO item por item (para cargar en el presupuesto de Gestion) sale de la hoja\r\n  Cotizador / Cotizador Off-Grid del xlsx. Esta propuesta es el INFORME al cliente.\r\n═══════════════════════════════════════════════════════════════════════════ -->\r\n<style>\r\n  :root{\r\n    --brand:#15694a; --brand2:#0d4a33; --brand-soft:#e7f1ec;\r\n    --solar:#e0980f; --solar2:#c07f06; --solar-soft:#fbf0d5;\r\n    --ink:#18231e; --ink2:#3b4a43; --muted:#6f7c74;\r\n    --page:#eceae3; --sheet:#ffffff; --line:#e4e6e0; --line2:#eef0ea;\r\n    --good:#1c8a5b; --good-soft:#e4f3ec;\r\n    --serif:Georgia,\"Iowan Old Style\",\"Times New Roman\",serif;\r\n    --sans:-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto,Helvetica,Arial,sans-serif;\r\n    --mono:ui-monospace,\"Cascadia Code\",\"SF Mono\",Menlo,Consolas,monospace;\r\n  }\r\n  *{box-sizing:border-box}\r\n  .page{background:var(--page); font-family:var(--sans); color:var(--ink);\r\n    line-height:1.55; -webkit-font-smoothing:antialiased; padding:26px 14px 70px}\r\n  .sheet{max-width:840px; margin:0 auto; background:var(--sheet);\r\n    box-shadow:0 6px 30px #0b2a1e1a; border-radius:4px; overflow:hidden}\r\n  .mono{font-family:var(--mono); font-variant-numeric:tabular-nums}\r\n  .pad{padding:34px 44px}\r\n  h2.sec{font-family:var(--sans); font-size:12px; letter-spacing:.16em; text-transform:uppercase;\r\n    color:var(--brand); margin:0 0 4px; font-weight:700}\r\n  h3.big{font-family:var(--serif); font-weight:400; font-size:27px; line-height:1.15;\r\n    letter-spacing:-.01em; margin:0 0 18px; color:var(--ink); text-wrap:balance}\r\n  p{margin:0 0 12px}\r\n  .lead{font-size:15.5px; color:var(--ink2)}\r\n\r\n  /* download bar */\r\n  .actions{max-width:840px; margin:0 auto 16px; display:flex; justify-content:flex-end; gap:10px}\r\n  .btn{font-family:var(--sans); font-size:13px; font-weight:600; border:none; cursor:pointer;\r\n    background:var(--brand); color:#fff; padding:10px 18px; border-radius:8px; display:inline-flex; gap:7px; align-items:center}\r\n  .btn:hover{background:var(--brand2)}\r\n  .btn svg{width:15px;height:15px}\r\n\r\n  /* ---- HERO ---- */\r\n  .hero{background:linear-gradient(150deg,var(--brand2),var(--brand) 70%); color:#eaf3ee; position:relative; overflow:hidden}\r\n  .topbar{display:flex; align-items:center; justify-content:space-between; gap:16px;\r\n    padding:22px 46px; background:#fff; border-bottom:1px solid var(--line)}\r\n  .topbar .brandlogo{height:54px; width:auto; display:block}\r\n  .topbar-label{font-size:11px; letter-spacing:.18em; text-transform:uppercase; color:var(--muted); font-weight:700; white-space:nowrap}\r\n  .hero-body{padding:46px 46px 42px; position:relative; z-index:1}\r\n  .ars-note{font-size:12.5px; color:#bcd6c9; margin:9px 0 0; max-width:52ch}\r\n  .hero::after{content:\"\"; position:absolute; right:-90px; top:-60px; width:320px; height:320px;\r\n    border-radius:50%; background:radial-gradient(circle at 30% 30%,#ffffff22,#ffffff00 70%)}\r\n  .sun{position:absolute; right:46px; top:40px; width:74px; height:74px; z-index:1}\r\n  .hero .eyebrow{font-size:11.5px; letter-spacing:.2em; text-transform:uppercase; color:var(--solar); font-weight:700; margin:0 0 12px}\r\n  .hero h1{font-family:var(--serif); font-weight:400; font-size:35px; line-height:1.1; letter-spacing:-.015em; margin:0 0 14px; max-width:15ch; text-wrap:balance}\r\n  .hero .who{font-size:14px; color:#cfe1d8; margin:0; border-top:1px solid #ffffff26; padding-top:16px; margin-top:22px}\r\n  .hero .who b{color:#fff}\r\n\r\n  /* ---- KPI strip ---- */\r\n  .kpis{display:grid; grid-template-columns:repeat(4,1fr); gap:1px; background:var(--line); border-bottom:1px solid var(--line)}\r\n  .kpi{background:var(--sheet); padding:20px 18px; text-align:center}\r\n  .kpi .n{font-family:var(--serif); font-size:29px; line-height:1; color:var(--brand); margin:0 0 5px}\r\n  .kpi .n small{font-size:15px; color:var(--muted)}\r\n  .kpi .l{font-size:11px; color:var(--ink2); margin:0; letter-spacing:.02em}\r\n\r\n  /* generic blocks */\r\n  .block{border-top:1px solid var(--line2)}\r\n  .two{display:grid; grid-template-columns:1fr 1fr; gap:26px; align-items:center}\r\n\r\n  .factbox{background:var(--brand-soft); border-radius:12px; padding:20px 22px}\r\n  .factrow{display:flex; justify-content:space-between; padding:8px 0; border-bottom:1px solid #ffffff; font-size:14px}\r\n  .factrow:last-child{border-bottom:none}\r\n  .factrow .k{color:var(--ink2)} .factrow .v{font-family:var(--mono); font-weight:700; color:var(--brand2)}\r\n  .factrow.hl .v{color:var(--solar2); font-size:16px}\r\n\r\n  /* equipment list */\r\n  .equip{list-style:none; padding:0; margin:14px 0 0}\r\n  .equip li{display:flex; gap:12px; padding:11px 0; border-top:1px solid var(--line2); font-size:14px}\r\n  .equip li:first-child{border-top:none}\r\n  .equip .q{font-family:var(--mono); font-weight:700; color:var(--brand); min-width:34px}\r\n  .equip .d b{display:block; color:var(--ink)} .equip .d span{color:var(--muted); font-size:12.5px}\r\n\r\n  .tech{display:flex; flex-wrap:wrap; gap:8px; margin-top:16px}\r\n  .chip{font-size:12px; background:var(--good-soft); color:var(--good); border-radius:999px; padding:5px 12px; font-weight:600; display:inline-flex; gap:5px; align-items:center}\r\n\r\n  /* savings compare bars */\r\n  .cmp{margin:8px 0 4px}\r\n  .cmp .barrow{margin-bottom:16px}\r\n  .cmp .barlbl{display:flex; justify-content:space-between; font-size:13px; margin-bottom:5px}\r\n  .cmp .barlbl b{font-family:var(--mono)}\r\n  .bar{height:26px; border-radius:6px; position:relative; background:var(--line2)}\r\n  .bar > i{position:absolute; left:0; top:0; bottom:0; border-radius:6px; display:block}\r\n  .bar.now > i{width:100%; background:linear-gradient(90deg,#b23b2e,#d1503f)}\r\n  .bar.sol > i{width:83%; background:linear-gradient(90deg,var(--brand2),var(--brand))}\r\n  .saved{font-size:13px; color:var(--good); font-weight:700; margin-top:2px}\r\n\r\n  /* projection chart */\r\n  .chart{margin-top:8px; padding:18px 4px 4px}\r\n  .bars{display:flex; align-items:flex-end; gap:7px; height:150px; border-bottom:2px solid var(--line); position:relative}\r\n  .bars .col{flex:1; display:flex; flex-direction:column; justify-content:flex-end; align-items:center; height:100%; position:relative}\r\n  .bars .col > i{width:100%; max-width:34px; background:linear-gradient(180deg,#3ba173,var(--brand)); border-radius:4px 4px 0 0; display:block}\r\n  .bars .col.pay > i{background:linear-gradient(180deg,var(--solar),var(--solar2))}\r\n  .bars .yl{font-size:10px; color:var(--muted); margin-top:5px}\r\n  .invline{position:absolute; left:0; right:0; border-top:2px dashed var(--solar2); z-index:2}\r\n  .invtag{position:absolute; right:0; font-size:10.5px; color:var(--solar2); font-weight:700; background:var(--sheet); padding:0 4px; transform:translateY(-50%)}\r\n  .caption{font-size:11.5px; color:var(--muted); margin-top:12px; text-align:center}\r\n  .radchart{margin:16px 0 8px; padding:14px 8px 6px; background:#f7f9fa; border:1px solid var(--line); border-radius:11px}\r\n  .radhead{font-size:12.5px; color:var(--ink2); margin:0 0 4px; padding:0 4px}\r\n  .radhead b{color:#15694a}\r\n  .radleg{color:#b23b2e; font-weight:600}\r\n  .radchart .caption{margin-top:8px}\r\n\r\n  /* benefits */\r\n  .bens{display:grid; grid-template-columns:1fr 1fr; gap:14px; margin-top:4px}\r\n  .ben{display:flex; gap:13px; padding:15px; background:#faf9f5; border:1px solid var(--line); border-radius:11px}\r\n  .ben .ic{width:34px;height:34px; flex-shrink:0; color:var(--brand); background:var(--brand-soft); border-radius:9px; display:flex; align-items:center; justify-content:center}\r\n  .ben .ic svg{width:19px;height:19px}\r\n  .ben b{display:block; font-size:14px; margin-bottom:2px}\r\n  .ben p{margin:0; font-size:12.8px; color:var(--muted)}\r\n\r\n  /* investment */\r\n  .invest{background:linear-gradient(150deg,#12352680,var(--brand2)); color:#eaf3ee; border-radius:16px; padding:28px 30px; margin-top:6px}\r\n  .invest .price{display:flex; align-items:baseline; gap:12px; flex-wrap:wrap}\r\n  .invest .price .big{font-family:var(--serif); font-size:44px; line-height:1; color:#fff}\r\n  .invest .price .ars{font-family:var(--mono); font-size:15px; color:#bcd6c9}\r\n  .invest .tag{font-size:12px; letter-spacing:.14em; text-transform:uppercase; color:var(--solar); font-weight:700; margin:0 0 6px}\r\n  .invest .incl{display:grid; grid-template-columns:1fr 1fr; gap:6px 20px; margin:20px 0 0; font-size:13px; list-style:none; padding:16px 0 0; border-top:1px solid #ffffff26}\r\n  .invest .incl li{display:flex; gap:8px; color:#dbe9e2}\r\n  .invest .incl li svg{width:15px;height:15px;color:var(--solar); flex-shrink:0; margin-top:2px}\r\n  .cond{font-size:12.5px; color:var(--muted); margin-top:14px}\r\n  .cond b{color:var(--ink2)}\r\n\r\n  /* steps + footer */\r\n  .steps{counter-reset:s; list-style:none; padding:0; margin:14px 0 0; display:grid; gap:12px}\r\n  .steps li{counter-increment:s; display:flex; gap:14px; align-items:flex-start; font-size:14px}\r\n  .steps li::before{content:counter(s); font-family:var(--mono); font-weight:700; color:#fff; background:var(--brand);\r\n    width:26px;height:26px;border-radius:50%; display:flex;align-items:center;justify-content:center; font-size:13px; flex-shrink:0}\r\n  .foot{background:var(--brand2); color:#bcd6c9; font-size:12.5px; text-align:center; padding:22px}\r\n  .foot b{color:#fff; display:block; margin-bottom:3px; font-size:14px}\r\n  .disc{font-size:11px; color:var(--muted); padding:16px 44px 4px; text-align:center; line-height:1.5}\r\n\r\n  @media(max-width:720px){\r\n    .pad{padding:26px 22px} .kpis{grid-template-columns:repeat(2,1fr)}\r\n    .two{grid-template-columns:1fr; gap:18px} .bens{grid-template-columns:1fr}\r\n    .invest .incl{grid-template-columns:1fr} .hero h1{font-size:28px} .sun{width:56px;height:56px;right:22px;top:26px}\r\n    .invest .price .big{font-size:36px}\r\n  }\r\n  @media print{\r\n    @page{size:A4; margin:12mm}\r\n    .page{background:#fff; padding:0}\r\n    .actions{display:none}\r\n    .sheet{box-shadow:none; max-width:none; border-radius:0}\r\n    .block,.invest,.factbox,.ben,.chart{break-inside:avoid}\r\n    .hero,.invest,.kpi .n,.foot{-webkit-print-color-adjust:exact; print-color-adjust:exact}\r\n  }\r\n</style>\r\n\r\n<div class=\"page\">\r\n\r\n  <div class=\"actions\">\r\n    <button class=\"btn\" onclick=\"window.print()\">\r\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M6 9V2h12v7M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2M6 14h12v8H6z\"/></svg>\r\n      Descargar / Imprimir PDF\r\n    </button>\r\n  </div>\r\n\r\n  <div class=\"sheet\">\r\n\r\n    <!-- TOP BAR (logo real FEBECOS energía solar) -->\r\n    <div class=\"topbar\">\r\n      <img class=\"brandlogo\" src=\"data:image/png;base64,\" alt=\"FEBECOS Energía Solar®\">\r\n      <span class=\"topbar-label\">Propuesta Comercial</span>\r\n    </div>\r\n\r\n    <!-- HERO -->\r\n    <div class=\"hero\">\r\n      <svg class=\"sun\" viewBox=\"0 0 100 100\" fill=\"none\" stroke=\"#e0980f\" stroke-width=\"4\"><circle cx=\"50\" cy=\"50\" r=\"17\" fill=\"#e0980f22\"/><g stroke-linecap=\"round\"><path d=\"M50 8v13M50 79v13M8 50h13M79 50h13M20 20l9 9M71 71l9 9M80 20l-9 9M29 71l-9 9\"/></g></svg>\r\n      <div class=\"hero-body\">\r\n        <p class=\"eyebrow\">Propuesta de Energía Solar</p>\r\n        <h1>Generá tu propia energía y reducí tu factura de luz</h1>\r\n        <p style=\"font-size:15px;color:#cfe1d8;max-width:46ch;margin:0\">Sistema solar fotovoltaico <b style=\"color:#fff\">1,16 kWp monofásico</b> con inyección cero, dimensionado a partir de tu consumo real.</p>\r\n        <p class=\"who\">Preparado para <b>Edgardo Jose Bouvier</b> — Carabelas (Salto), Buenos Aires &nbsp;·&nbsp; Ref. presupuesto <b>PREV-2026-0325</b> &nbsp;·&nbsp; 07/07/2026</p>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- KPIs -->\r\n    <div class=\"kpis\">\r\n      <div class=\"kpi\"><p class=\"n\">~50<small>%</small></p><p class=\"l\">de tu consumo<br>cubierto por el sol</p></div>\r\n      <div class=\"kpi\"><p class=\"n\">~$13<small>k</small></p><p class=\"l\">de ahorro por mes<br>(al valor de hoy)</p></div>\r\n      <div class=\"kpi\"><p class=\"n\">~10<small> años</small></p><p class=\"l\">y se paga solo<br>con el ahorro</p></div>\r\n      <div class=\"kpi\"><p class=\"n\">25<small> años</small></p><p class=\"l\">de vida útil<br>de los paneles</p></div>\r\n    </div>\r\n\r\n    <!-- SITUACIÓN -->\r\n    <div class=\"block pad\">\r\n      <div class=\"two\">\r\n        <div>\r\n          <h2 class=\"sec\">Tu situación hoy</h2>\r\n          <h3 class=\"big\">Cada mes pagás una factura que solo sube</h3>\r\n          <p class=\"lead\">Tu consumo es estable y las tarifas no paran de subir. Ese gasto es dinero que se va y no vuelve. La energía solar convierte parte de ese gasto fijo en una inversión propia que te acompaña por décadas.</p>\r\n        </div>\r\n        <div class=\"factbox\">\r\n          <div class=\"factrow hl\"><span class=\"k\">Factura mensual</span><span class=\"v\">$78.130</span></div>\r\n          <div class=\"factrow\"><span class=\"k\">Consumo promedio</span><span class=\"v\">272 kWh/mes</span></div><div class=\"factrow\"><span class=\"k\">Consumo anual · rango</span><span class=\"v\">3.274 kWh · 171–516</span></div>\r\n          <div class=\"factrow\"><span class=\"k\">Tarifa</span><span class=\"v\">Residencial (tramo 0–300)</span></div>\r\n          <div class=\"factrow\"><span class=\"k\">Conexión</span><span class=\"v\">Monofásica 220 V</span></div>\r\n          <div class=\"factrow\"><span class=\"k\">Distribuidora</span><span class=\"v\">Coop. de Salto</span></div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- SOLUCIÓN -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">La solución</h2>\r\n      <h3 class=\"big\">Un sistema solar de 1,16 kWp con inyección cero</h3>\r\n      <p class=\"lead\" style=\"max-width:60ch\">De día generás y consumís tu propia energía; el limitador evita volcar excedente a la red (inyección cero), por eso no hace falta trámite de generación distribuida. Sin baterías, con monitoreo por app.</p>\r\n      <ul class=\"equip\">\r\n        <li><span class=\"q\">2×</span><span class=\"d\"><b>Paneles Amerisolar 580&nbsp;Wp N-Type</b><span>1,16 kWp — monocristalinos, alta eficiencia</span></span></li>\r\n        <li><span class=\"q\">1×</span><span class=\"d\"><b>Microinversor Growatt 1000&nbsp;W con WiFi</b><span>2 MPPT por panel · monitoreo por app · 5 años de garantía</span></span></li>\r\n        <li><span class=\"q\">1×</span><span class=\"d\"><b>Estructura coplanar + protecciones + puesta a tierra + inyección cero</b><span>montaje para chapa, descargador CC, térmica CA, puesta a tierra y limitador de inyección</span></span></li>\r\n      </ul>\r\n      <div class=\"tech\">\r\n        <span class=\"chip\">✔ Microinversor validado (44 V en rango MPPT)</span>\r\n        <span class=\"chip\">✔ Inyección cero — sin trámite de GD</span>\r\n        <span class=\"chip\">✔ Conexión monofásica 220 V</span>\r\n        <span class=\"chip\">✔ Monitoreo por app (WiFi)</span>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- COMO SE CONECTA -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Cómo se conecta</h2>\r\n      <h3 class=\"big\">Dos paneles, un microinversor, inyección cero</h3>\r\n      <p class=\"lead\" style=\"max-width:64ch\">Cada panel entrega ~44 V y va a una <b>entrada MPPT</b> del microinversor Growatt (tiene dos). El micro convierte a <b>220 V</b> y por un solo cable llega al tablero; el <b>limitador Growatt</b> evita volcar excedente a la red — inyección cero, sin trámite de generación distribuida.</p>\r\n      <div style=\"margin-top:16px;overflow-x:auto\"><svg viewBox=\"0 0 820 320\" xmlns=\"http://www.w3.org/2000/svg\" role=\"img\" style=\"max-width:100%;height:auto;print-color-adjust:exact;-webkit-print-color-adjust:exact\" font-family=\"Georgia,serif\">\r\n<title>Conexion de 2 paneles a un microinversor Growatt NEO1000M-X con inyeccion cero</title>\r\n<rect x=\"18\" y=\"34\" width=\"126\" height=\"72\" rx=\"8\" fill=\"#e9eef3\" stroke=\"#2c5f8a\" stroke-width=\"2\"/>\r\n<text x=\"81\" y=\"64\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#22405c\">Panel 580 W</text>\r\n<text x=\"81\" y=\"84\" text-anchor=\"middle\" font-size=\"12\" fill=\"#4a6377\">&#8776; 44 V CC</text>\r\n<rect x=\"18\" y=\"170\" width=\"126\" height=\"72\" rx=\"8\" fill=\"#e9eef3\" stroke=\"#2c5f8a\" stroke-width=\"2\"/>\r\n<text x=\"81\" y=\"200\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"700\" fill=\"#22405c\">Panel 580 W</text>\r\n<text x=\"81\" y=\"220\" text-anchor=\"middle\" font-size=\"12\" fill=\"#4a6377\">&#8776; 44 V CC</text>\r\n<defs><marker id=\"ar\" markerWidth=\"9\" markerHeight=\"9\" refX=\"7\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L7,3 L0,6 Z\" fill=\"#6f7c74\"/></marker></defs>\r\n<path d=\"M144,70 C185,70 185,112 224,112\" fill=\"none\" stroke=\"#6f7c74\" stroke-width=\"2.5\" marker-end=\"url(#ar)\"/>\r\n<path d=\"M144,206 C185,206 185,198 224,198\" fill=\"none\" stroke=\"#6f7c74\" stroke-width=\"2.5\" marker-end=\"url(#ar)\"/>\r\n<rect x=\"228\" y=\"66\" width=\"196\" height=\"180\" rx=\"12\" fill=\"#15694a\"/>\r\n<circle cx=\"228\" cy=\"112\" r=\"6\" fill=\"#e0980f\"/><text x=\"246\" y=\"116\" font-size=\"11\" fill=\"#cde4d9\">MPPT 1</text>\r\n<circle cx=\"228\" cy=\"198\" r=\"6\" fill=\"#e0980f\"/><text x=\"246\" y=\"202\" font-size=\"11\" fill=\"#cde4d9\">MPPT 2</text>\r\n<text x=\"326\" y=\"132\" text-anchor=\"middle\" font-size=\"15\" font-weight=\"700\" fill=\"#ffffff\">Microinversor</text>\r\n<text x=\"326\" y=\"152\" text-anchor=\"middle\" font-size=\"13\" fill=\"#eafaf2\">Growatt NEO1000M-X</text>\r\n<text x=\"326\" y=\"176\" text-anchor=\"middle\" font-size=\"12\" fill=\"#bfe3d2\">2 entradas MPPT</text>\r\n<text x=\"326\" y=\"222\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#ffd98a\">CC &#8594; CA</text>\r\n<path d=\"M424,156 L494,156\" fill=\"none\" stroke=\"#6f7c74\" stroke-width=\"2.5\" marker-end=\"url(#ar)\"/>\r\n<text x=\"459\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" fill=\"#6f7c74\">220 V CA</text>\r\n<rect x=\"498\" y=\"86\" width=\"196\" height=\"140\" rx=\"10\" fill=\"#ffffff\" stroke=\"#c9cdc7\" stroke-width=\"2\"/>\r\n<text x=\"596\" y=\"112\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#3b4a43\">Tablero CA (termica 2P)</text>\r\n<rect x=\"516\" y=\"128\" width=\"160\" height=\"72\" rx=\"8\" fill=\"#fbf0d5\" stroke=\"#e0980f\" stroke-width=\"2\"/>\r\n<text x=\"596\" y=\"152\" text-anchor=\"middle\" font-size=\"13\" font-weight=\"700\" fill=\"#8a5a04\">Limitador Growatt</text>\r\n<text x=\"596\" y=\"172\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#b5791f\">INYECCION CERO</text>\r\n<text x=\"596\" y=\"189\" text-anchor=\"middle\" font-size=\"10.5\" fill=\"#8a5a04\">no vuelca a la red</text>\r\n<path d=\"M694,156 L730,156\" fill=\"none\" stroke=\"#6f7c74\" stroke-width=\"2.5\" marker-end=\"url(#ar)\"/>\r\n<line x1=\"762\" y1=\"120\" x2=\"762\" y2=\"196\" stroke=\"#6f7c74\" stroke-width=\"3\"/>\r\n<line x1=\"748\" y1=\"132\" x2=\"776\" y2=\"132\" stroke=\"#6f7c74\" stroke-width=\"3\"/>\r\n<line x1=\"752\" y1=\"150\" x2=\"772\" y2=\"150\" stroke=\"#6f7c74\" stroke-width=\"3\"/>\r\n<text x=\"762\" y=\"214\" text-anchor=\"middle\" font-size=\"12\" font-weight=\"700\" fill=\"#6f7c74\">Red</text>\r\n<text x=\"326\" y=\"286\" text-anchor=\"middle\" font-size=\"12.5\" fill=\"#6f7c74\">1 microinversor = 2 paneles &#183; un panel en cada entrada MPPT</text>\r\n</svg></div>\r\n    </div>\r\n\r\n    <!-- GENERACIÓN Y AHORRO -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Generación y ahorro</h2>\r\n      <h3 class=\"big\">Genera ~1.650 kWh por año — para consumir de día</h3>\r\n      <p class=\"lead\" style=\"max-width:62ch\">El sistema produce de día; lo que consumís en ese momento se descuenta directo de tu factura. Con inyección cero conviene volcar el consumo diurno (bomba, heladera, aire, herramientas) a las horas de sol.</p>\r\n      <div class=\"radchart\">\r\n        <div class=\"radhead\"><b>Generación solar mensual (kWh)</b> <span class=\"radleg\">— tu consumo real (kWh)</span></div>\r\n        <div id=\"radbars\"></div>\r\n        <p class=\"caption\">Barras verdes = <b>generación solar estimada</b> (PVGIS, Salto/Carabelas · lat −34,29) · línea roja = <b>tu consumo real</b> (histórico de tu factura). Generación ~1.650 kWh/año · consumo ~3.274 kWh/año → el sol cubre ~50%; el resto lo tomás de la red (noche y picos de verano).</p>\r\n      </div>\r\n      <div class=\"cmp\">\r\n        <div class=\"barrow\">\r\n          <div class=\"barlbl\"><span>Factura hoy</span><b>$78.130</b></div>\r\n          <div class=\"bar now\"><i></i></div>\r\n        </div>\r\n        <div class=\"barrow\">\r\n          <div class=\"barlbl\"><span>Factura estimada con solar</span><b>~$65.000</b></div>\r\n          <div class=\"bar sol\"><i></i></div>\r\n          <div class=\"saved\">▼ Ahorrás ~$13.000 por mes  ·  ~$156.000 por año</div>\r\n        </div>\r\n      </div>\r\n      <p style=\"font-size:12.5px;color:var(--muted);margin-top:10px\"><b>Nota honesta:</b> de tu factura de <b>$78.130</b>, cerca de <b>la mitad (~$40.000) son cargos fijos</b> (cuota fija, alumbrado público, ambulancia, gas) que el sol <b>no</b> baja. Tal como está (<b>inyección cero</b>) aprovechás el mediodía → ~$13.000/mes. <b>💡 Si hacés el trámite de Generación Distribuida</b> y dejás inyectar el excedente a la red (medidor bidireccional, según lo acepte la cooperativa), recuperás <b>~$8.000/mes más</b> → <b>~$21.000/mes</b> y el repago baja a ~6 años. Para capturar también la noche sin trámite, va la opción con batería.</p>\r\n    </div>\r\n\r\n    <!-- RETORNO -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Retorno de la inversión</h2>\r\n      <h3 class=\"big\">Se paga en ~10 años (o ~6 si inyectás a la red). Después, casi gratis</h3>\r\n      <div class=\"chart\">\r\n        <div class=\"bars\" id=\"bars\">\r\n          <div class=\"invline\" style=\"bottom:97%\"><span class=\"invtag\">Inversión ~$1,6 M</span></div>\r\n        </div>\r\n        <p class=\"caption\">Ahorro acumulado en pesos de hoy (conservador, sin ajustar por aumentos de tarifa). Sin inyectar, la inversión se recupera cerca del <b>año&nbsp;10</b> (pesos de hoy; con los aumentos de tarifa, antes). Si inyectás el excedente (GD), baja a ~6 años.</p>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- BENEFICIOS -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Por qué conviene</h2>\r\n      <h3 class=\"big\">Más que un ahorro: una inversión que se protege sola</h3>\r\n      <div class=\"bens\">\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M12 2l8 3v6c0 5-3.5 8.5-8 11-4.5-2.5-8-6-8-11V5z\"/></svg></span><div><b>Escudo contra los aumentos</b><p>Mientras la tarifa sube, tu ahorro sube con ella. Fijás tu costo de energía.</p></div></div>\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"4\"/><path stroke-linecap=\"round\" d=\"M12 2v3M12 19v3M2 12h3M19 12h3M5 5l2 2M17 17l2 2M19 5l-2 2M7 17l-2 2\"/></svg></span><div><b>Energía limpia y renovable</b><p>Usás energía limpia y renovable en tu casa/campo, reduciendo tu huella.</p></div></div>\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M14 6a3.5 3.5 0 0 1-4.6 4.6L4 16v4h4l5.4-5.4A3.5 3.5 0 0 1 18 10l3-3-3-3-3 2z\"/></svg></span><div><b>Bajísimo mantenimiento</b><p>Sin partes móviles. Los paneles trabajan solos por décadas.</p></div></div>\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 11l9-7 9 7M5 10v10h14V10\"/></svg></span><div><b>Revaloriza la propiedad</b><p>Una instalación solar suma valor real a tu propiedad.</p></div></div>\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 3v18h18M7 14l4-4 3 3 5-6\"/></svg></span><div><b>Monitoreo por app</b><p>Ves tu generación y ahorro en tiempo real desde el celular (WiFi incluido).</p></div></div>\r\n        <div class=\"ben\"><span class=\"ic\"><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M9 2v6M15 2v6M8 8h8v3a4 4 0 0 1-8 0zM12 15v7\"/></svg></span><div><b>Respaldo de red permanente</b><p>Sistema on-grid: nunca te quedás sin energía, la red siempre está de respaldo.</p></div></div>\r\n      </div>\r\n    </div>\r\n\r\n    <!-- INVERSIÓN -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Tu inversión</h2>\r\n      <div class=\"invest\">\r\n        <p class=\"tag\">Equipo completo · IVA incluido</p>\r\n        <div class=\"price\"><span class=\"big\">USD 1.260</span></div>\r\n        <p class=\"ars-note\">Equivalente en pesos según la cotización del <b>dólar billete Banco Nación</b> del día de la facturación.</p>\r\n        <ul class=\"incl\">\r\n          <li><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\"><path d=\"M5 13l4 4L19 7\"/></svg> 2× Paneles Amerisolar 580W N-Type (1,16 kWp)</li>\r\n          <li><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\"><path d=\"M5 13l4 4L19 7\"/></svg> Microinversor Growatt 1000W con WiFi</li>\r\n          <li><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\"><path d=\"M5 13l4 4L19 7\"/></svg> Estructura coplanar para chapa (con clamps)</li>\r\n          <li><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\"><path d=\"M5 13l4 4L19 7\"/></svg> Protecciones CC/CA + cable solar + puesta a tierra + limitador Growatt + MC4</li>\r\n        </ul>\r\n      </div>\r\n      <p class=\"cond\"><b>No incluye:</b> instalación / mano de obra (se cotiza aparte según el relevamiento del techo) ni flete a Salto. &nbsp;<b>Condiciones:</b> pago anticipado por transferencia · entrega a confirmar según stock · validez 48 horas · precios en USD billete.</p>\r\n    </div>\r\n\r\n    <!-- PASOS -->\r\n    <div class=\"block pad\">\r\n      <h2 class=\"sec\">Próximos pasos</h2>\r\n      <ol class=\"steps\">\r\n        <li><div><b>Visita técnica al techo</b> — relevamos el lugar y confirmamos el layout definitivo.</div></li>\r\n        <li><div><b>Presupuesto de instalación</b> — mano de obra e ingeniería, a medida del sitio.</div></li>\r\n        <li><div><b>Confirmación y puesta en marcha</b> — validamos stock, coordinamos entrega e instalamos con el limitador en modo inyección cero.</div></li>\r\n      </ol>\r\n    </div>\r\n\r\n    <div class=\"foot\">\r\n      <b>FEBECOS · Energía Solar</b>\r\n      cotiza@febecos.com &nbsp;·&nbsp; +54 9 11 2575-0323 &nbsp;·&nbsp; febecos.com &nbsp;·&nbsp; Rojas 441, CABA\r\n    </div>\r\n  </div>\r\n\r\n  <p class=\"disc\">Propuesta orientativa preparada a partir de la factura provista. Valores de generación y ahorro estimados según irradiación de la zona y consumo actual; el resultado real puede variar con el uso, el clima y las tarifas vigentes. El equivalente en pesos se ajusta al dólar BNA venta del día de la facturación. Documento no válido como factura.</p>\r\n\r\n</div>\r\n\r\n<script>\r\n(function(){\r\n  // Ahorro acumulado (millones ARS, pesos de hoy) — años 1..10\r\n  var acc=[0.16,0.31,0.47,0.62,0.78,0.94,1.09,1.25,1.40,1.56];\r\n  var max=1.60;\r\n  var bars=document.getElementById('bars');\r\n  for(var i=0;i<acc.length;i++){\r\n    var col=document.createElement('div');\r\n    col.className='col'+((i<10)?' pay':'');\r\n    var h=Math.round(acc[i]/max*100);\r\n    col.innerHTML='<i style=\"height:'+h+'%\"></i><span class=\"yl\">A'+(i+1)+'</span>';\r\n    col.title='Año '+(i+1)+': $'+acc[i].toFixed(1)+' M acumulados';\r\n    bars.appendChild(col);\r\n  }\r\n\r\n  // Generación (kWh) vs radiación (kWh/m²) mensual — PVGIS Colón, 11,5 kWp\r\n  var gen=[187,152,146,115,92,81,85,117,135,162,181,195];\r\n  var consumo=[516,433,371,234,196,191,171,186,225,192,212,347]; /* CONSUMO REAL mensual del lugar (kWh) - de la factura/historico. REEMPLAZAR por los datos del cliente */\r\n  var mes=['E','F','M','A','M','J','J','A','S','O','N','D'];\r\n  var Wc=680,x0=16,x1=664,base=170,topc=12,gmax=560,rmax=225,nc=12,slot=(x1-x0)/nc,bw=slot*0.56;\r\n  var svg='<svg viewBox=\"0 0 '+Wc+' 196\" width=\"100%\" style=\"display:block\">';\r\n  for(var j=0;j<nc;j++){\r\n    var cx=x0+slot*j+slot/2, bh=(gen[j]/gmax)*(base-topc);\r\n    svg+='<rect x=\"'+(cx-bw/2).toFixed(1)+'\" y=\"'+(base-bh).toFixed(1)+'\" width=\"'+bw.toFixed(1)+'\" height=\"'+bh.toFixed(1)+'\" rx=\"3\" fill=\"#15694a\"/>';\r\n    svg+='<text x=\"'+cx.toFixed(1)+'\" y=\"'+(base-bh-4).toFixed(1)+'\" text-anchor=\"middle\" font-size=\"9.5\" font-weight=\"bold\" fill=\"#15694a\" font-family=\"Arial\">'+gen[j].toLocaleString('es-AR')+'</text>';\r\n    svg+='<text x=\"'+cx.toFixed(1)+'\" y=\"'+(base+16)+'\" text-anchor=\"middle\" font-size=\"11\" fill=\"#6f7c74\" font-family=\"Arial\">'+mes[j]+'</text>';\r\n  }\r\n  var pts='';\r\n  for(var j=0;j<nc;j++){ var cx=x0+slot*j+slot/2, y=base-(consumo[j]/gmax)*(base-topc); pts+=cx.toFixed(1)+','+y.toFixed(1)+' '; }\r\n  svg+='<polyline points=\"'+pts.trim()+'\" fill=\"none\" stroke=\"#b23b2e\" stroke-width=\"2.5\"/>';\r\n  for(var j=0;j<nc;j++){ var cx=x0+slot*j+slot/2, y=base-(consumo[j]/gmax)*(base-topc); svg+='<circle cx=\"'+cx.toFixed(1)+'\" cy=\"'+y.toFixed(1)+'\" r=\"2.8\" fill=\"#b23b2e\"/>'; }\r\n  svg+='</svg>';\r\n  var rb=document.getElementById('radbars'); if(rb) rb.innerHTML=svg;\r\n})();\r\n</script>\r\n";
